import{_ as e,c as s,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Actualizar Skills: Mantener Skills Actualizados | opencode-openskills","description":"Aprende el comando OpenSkills update para actualizar skills instalados. Soporta actualización masiva de todos los skills o skills específicos, comprende las diferencias entre actualización de rutas locales y repositorios git, mantén skills en la versión más reciente.","frontmatter":{"title":"Actualizar Skills: Mantener Skills Actualizados | opencode-openskills","sidebarTitle":"Actualización en un Click","subtitle":"Actualizar Skills: Mantener Skills Actualizados","description":"Aprende el comando OpenSkills update para actualizar skills instalados. Soporta actualización masiva de todos los skills o skills específicos, comprende las diferencias entre actualización de rutas locales y repositorios git, mantén skills en la versión más reciente.","tags":["skills","actualización","git"],"prerequisite":["start-installation","start-first-skill"],"order":5},"headers":[],"relativePath":"es/numman-ali/openskills/platforms/update-skills/index.md","filePath":"es/numman-ali/openskills/platforms/update-skills/index.md"}'),t={name:"es/numman-ali/openskills/platforms/update-skills/index.md"};function o(n,a,r,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="actualizar-skills-mantener-skills-sincronizados-con-el-repositorio-fuente" tabindex="-1">Actualizar Skills: Mantener Skills Sincronizados con el Repositorio Fuente <a class="header-anchor" href="#actualizar-skills-mantener-skills-sincronizados-con-el-repositorio-fuente" aria-label="Permalink to &quot;Actualizar Skills: Mantener Skills Sincronizados con el Repositorio Fuente&quot;">​</a></h1><h2 id="lo-que-podras-hacer" tabindex="-1">Lo Que Podrás Hacer <a class="header-anchor" href="#lo-que-podras-hacer" aria-label="Permalink to &quot;Lo Que Podrás Hacer&quot;">​</a></h2><p>Esta lección te enseña cómo mantener los skills de OpenSkills siempre en la versión más reciente. Con el comando OpenSkills update, podrás:</p><ul><li>Actualizar todos los skills instalados con un solo clic</li><li>Actualizar solo algunos skills específicos</li><li>Comprender las diferencias de actualización para diferentes fuentes de instalación</li><li>Diagnosticar las causas de fallas en las actualizaciones</li></ul><h2 id="tu-dilema-actual" tabindex="-1">Tu Dilema Actual <a class="header-anchor" href="#tu-dilema-actual" aria-label="Permalink to &quot;Tu Dilema Actual&quot;">​</a></h2><p>Los repositorios de skills se actualizan constantemente—los autores pueden corregir bugs, agregar nuevas funciones, mejorar la documentación. Pero los skills que instalaste siguen siendo versiones antiguas.</p><p>Es posible que ya te hayas encontrado con estas situaciones:</p><ul><li>La documentación del skill dice &quot;soporta cierta función&quot;, pero tu agente de IA dice que no la conoce</li><li>El skill ha actualizado mejores mensajes de error, pero sigues viendo los antiguos</li><li>Un bug de instalación ya fue corregido, pero sigues afectado por él</li></ul><p><strong>Eliminar y reinstalar cada vez es demasiado molesto</strong>—necesitas una forma eficiente de actualización.</p><h2 id="cuando-usar-este-truco" tabindex="-1">Cuándo Usar Este Truco <a class="header-anchor" href="#cuando-usar-este-truco" aria-label="Permalink to &quot;Cuándo Usar Este Truco&quot;">​</a></h2><p>Escenarios típicos para usar el comando <code>update</code>:</p><table tabindex="0"><thead><tr><th>Escenario</th><th>Acción</th></tr></thead><tbody><tr><td>Descubrir que un skill tiene actualizaciones</td><td>Ejecutar <code>openskills update</code></td></tr><tr><td>Solo actualizar unos pocos skills</td><td><code>openskills update skill1,skill2</code></td></tr><tr><td>Prueba de skills desarrollados localmente</td><td>Actualizar desde ruta local</td></tr><tr><td>Actualizar desde repositorios GitHub</td><td>Clonar automáticamente el código más reciente</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Recomendaciones de frecuencia de actualización</p><ul><li><strong>Skills de la comunidad</strong>: Actualizar mensualmente para obtener mejoras recientes</li><li><strong>Skills que desarrollas tú</strong>: Actualizar manualmente después de cada modificación</li><li><strong>Skills de ruta local</strong>: Actualizar después de cada cambio de código</li></ul></div><h2 id="🎒-preparativos-antes-de-empezar" tabindex="-1">🎒 Preparativos Antes de Empezar <a class="header-anchor" href="#🎒-preparativos-antes-de-empezar" aria-label="Permalink to &quot;🎒 Preparativos Antes de Empezar&quot;">​</a></h2><p>Antes de empezar, confirma que has completado:</p><ul><li>[x] Instalado OpenSkills (ver <a href="./../../start/installation/">Instalar OpenSkills</a>)</li><li>[x] Instalado al menos un skill (ver <a href="./../../start/first-skill/">Instalar el primer skill</a>)</li><li>[x] Si fue instalado desde GitHub, confirmar conexión a red</li></ul><h2 id="idea-principal" tabindex="-1">Idea Principal <a class="header-anchor" href="#idea-principal" aria-label="Permalink to &quot;Idea Principal&quot;">​</a></h2><p>El mecanismo de actualización de OpenSkills es simple:</p><p><strong>Cada vez que se instala se registra la información de origen → Al actualizar se vuelve a copiar desde el origen original</strong></p><div class="info custom-block"><p class="custom-block-title">¿Por qué se necesita reinstalar?</p><p>Los skills de versiones antiguas (instalados sin registrar el origen) no se pueden actualizar. En este caso, necesitas reinstalar una vez, OpenSkills recordará el origen y luego podrás actualizar automáticamente.</p></div><p><strong>Formas de actualización para tres tipos de orígenes de instalación</strong>:</p><table tabindex="0"><thead><tr><th>Tipo de origen</th><th>Forma de actualización</th><th>Escenario aplicable</th></tr></thead><tbody><tr><td><strong>Ruta local</strong></td><td>Copiar directamente desde ruta local</td><td>Desarrollar tus propios skills</td></tr><tr><td><strong>Repositorio git</strong></td><td>Clonar código más reciente a directorio temporal</td><td>Instalar desde GitHub/GitLab</td></tr><tr><td><strong>Shorthand de GitHub</strong></td><td>Convertir a URL completa luego clonar</td><td>Instalar desde repositorio oficial de GitHub</td></tr></tbody></table><p>Al actualizar se omitirán los skills sin metadatos de origen y se listarán los nombres de los skills que necesitan reinstalación.</p><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-ver-skills-instalados" tabindex="-1">Paso 1: Ver Skills Instalados <a class="header-anchor" href="#paso-1-ver-skills-instalados" aria-label="Permalink to &quot;Paso 1: Ver Skills Instalados&quot;">​</a></h3><p>Primero confirma qué skills se pueden actualizar:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>Deberías ver</strong>: lista de skills instalados, incluyendo nombre, descripción y etiqueta de ubicación de instalación (project/global)</p><h3 id="paso-2-actualizar-todos-los-skills" tabindex="-1">Paso 2: Actualizar Todos los Skills <a class="header-anchor" href="#paso-2-actualizar-todos-los-skills" aria-label="Permalink to &quot;Paso 2: Actualizar Todos los Skills&quot;">​</a></h3><p>La forma más simple es actualizar todos los skills instalados:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Deberías ver</strong>: actualiza skills uno por uno, cada skill muestra el resultado de actualización</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Skipped: my-old-skill (no source metadata; re-install once to enable updates)</span></span>
<span class="line"><span>Summary: 2 updated, 1 skipped (3 total)</span></span></code></pre></div><details class="details custom-block"><summary>Significado de skills omitidos</summary><p>Si ves <code>Skipped: xxx (no source metadata)</code>, significa que este skill fue instalado antes de que se añadiera la función de actualización. Necesitas reinstalar una vez para habilitar la actualización automática.</p></details><h3 id="paso-3-actualizar-skills-especificos" tabindex="-1">Paso 3: Actualizar Skills Específicos <a class="header-anchor" href="#paso-3-actualizar-skills-especificos" aria-label="Permalink to &quot;Paso 3: Actualizar Skills Específicos&quot;">​</a></h3><p>Si solo quieres actualizar algunos skills específicos, pasa los nombres de los skills (separados por comas):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-workflow,check-branch-first</span></span></code></pre></div><p><strong>Deberías ver</strong>: solo se actualizaron los dos skills especificados</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Summary: 2 updated, 0 skipped (2 total)</span></span></code></pre></div><h3 id="paso-4-actualizar-skills-desarrollados-localmente" tabindex="-1">Paso 4: Actualizar Skills Desarrollados Localmente <a class="header-anchor" href="#paso-4-actualizar-skills-desarrollados-localmente" aria-label="Permalink to &quot;Paso 4: Actualizar Skills Desarrollados Localmente&quot;">​</a></h3><p>Si estás desarrollando un skill localmente, puedes actualizar desde la ruta local:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span></span></code></pre></div><p><strong>Deberías ver</strong>: el skill se vuelve a copiar desde la ruta local donde lo instalaste</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: my-skill</span></span>
<span class="line"><span>Summary: 1 updated, 0 skipped (1 total)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Flujo de trabajo de desarrollo local</p><p>Proceso de desarrollo:</p><ol><li>Instalar skill: <code>openskills install ./my-skill</code></li><li>Modificar código</li><li>Actualizar skill: <code>openskills update my-skill</code></li><li>Sincronizar a AGENTS.md: <code>openskills sync</code></li></ol></div><h3 id="paso-5-manejar-actualizaciones-fallidas" tabindex="-1">Paso 5: Manejar Actualizaciones Fallidas <a class="header-anchor" href="#paso-5-manejar-actualizaciones-fallidas" aria-label="Permalink to &quot;Paso 5: Manejar Actualizaciones Fallidas&quot;">​</a></h3><p>Si algunos skills fallan al actualizar, OpenSkills mostrará la causa detallada:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Situaciones que podrías ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skipped: git-workflow (git clone failed)</span></span>
<span class="line"><span>Skipped: my-skill (local source missing)</span></span>
<span class="line"><span>Missing source metadata (1): old-skill</span></span>
<span class="line"><span>Clone failed (1): git-workflow</span></span></code></pre></div><p><strong>Métodos de solución correspondientes</strong>:</p><table tabindex="0"><thead><tr><th>Mensaje de error</th><th>Causa</th><th>Método de solución</th></tr></thead><tbody><tr><td><code>no source metadata</code></td><td>Instalación de versión antigua</td><td>Reinstalar: <code>openskills install &lt;source&gt;</code></td></tr><tr><td><code>local source missing</code></td><td>Ruta local eliminada</td><td>Restaurar ruta local o reinstalar</td></tr><tr><td><code>SKILL.md missing at local source</code></td><td>Archivo local eliminado</td><td>Restaurar archivo SKILL.md</td></tr><tr><td><code>git clone failed</code></td><td>Problema de red o repositorio no existe</td><td>Verificar red o dirección del repositorio</td></tr><tr><td><code>SKILL.md not found in repo</code></td><td>Cambio de estructura de repositorio</td><td>Contactar autor del skill o actualizar subpath</td></tr></tbody></table><h2 id="punto-de-control-✅" tabindex="-1">Punto de Control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de Control ✅&quot;">​</a></h2><p>Confirma que has aprendido:</p><ul><li>[ ] Puedes usar <code>openskills update</code> para actualizar todos los skills</li><li>[ ] Puedes usar comas para separar y actualizar skills específicos</li><li>[ ] Comprendes el significado y solución de &quot;omitir&quot; skills</li><li>[ ] Conoces el proceso de actualización de skills desarrollados localmente</li></ul><h2 id="advertencias" tabindex="-1">Advertencias <a class="header-anchor" href="#advertencias" aria-label="Permalink to &quot;Advertencias&quot;">​</a></h2><h3 id="❌-errores-comunes" tabindex="-1">❌ Errores Comunes <a class="header-anchor" href="#❌-errores-comunes" aria-label="Permalink to &quot;❌ Errores Comunes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Error</th><th>Práctica Correcta</th></tr></thead><tbody><tr><td>Ver que fue omitido y no hacer nada</td><td>Reinstalar o solucionar el problema según el mensaje</td></tr><tr><td>Eliminar y reinstalar cada vez</td><td>Usar el comando <code>update</code> es más eficiente</td></tr><tr><td>No saber de dónde se instaló el skill</td><td>Usar <code>openskills list</code> para ver el origen</td></tr></tbody></table><h3 id="⚠️-precauciones" tabindex="-1">⚠️ Precauciones <a class="header-anchor" href="#⚠️-precauciones" aria-label="Permalink to &quot;⚠️ Precauciones&quot;">​</a></h3><p><strong>La actualización sobrescribirá modificaciones locales</strong></p><p>Si modificaste directamente los archivos del skill en el directorio de instalación, estas modificaciones serán sobrescritas al actualizar. La práctica correcta es:</p><ol><li>Modificar <strong>archivos fuente</strong> (ruta local o repositorio)</li><li>Luego ejecutar <code>openskills update</code></li></ol><p><strong>Los skills de enlace simbólico necesitan manejo especial</strong></p><p>Si el skill fue instalado a través de un enlace simbólico (ver <a href="./../../advanced/symlink-support/">Soporte de enlaces simbólicos</a>), la actualización volverá a crear el enlace, sin destruir la relación de enlace simbólico.</p><p><strong>Skills globales y de proyecto necesitan actualización separada</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Solo actualizar skills de proyecto (por defecto)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Actualizar skills globales necesita manejo separado</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># O usar el modo --universal para gestión unificada</span></span></code></pre></div><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de Esta Lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de Esta Lección&quot;">​</a></h2><p>Esta lección aprendimos la función de actualización de OpenSkills:</p><ul><li><strong>Actualización masiva</strong>: <code>openskills update</code> actualiza todos los skills con un clic</li><li><strong>Actualización específica</strong>: <code>openskills update skill1,skill2</code> actualiza skills específicos</li><li><strong>Consciencia del origen</strong>: Reconoce automáticamente rutas locales y repositorios git</li><li><strong>Avisos de error</strong>: Explica detalladamente las razones de omisión y métodos de solución</li></ul><p>La función de actualización mantiene los skills en la versión más reciente, asegurando que los skills que uses siempre contengan las últimas mejoras y correcciones.</p><h2 id="avance-de-la-proxima-leccion" tabindex="-1">Avance de la Próxima Lección <a class="header-anchor" href="#avance-de-la-proxima-leccion" aria-label="Permalink to &quot;Avance de la Próxima Lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../remove-skills/">Eliminar skills</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo usar el comando interactivo <code>manage</code> para eliminar skills</li><li>Cómo usar el comando <code>remove</code> para eliminación programática</li><li>Precauciones después de eliminar skills</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de Código Fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicación del código fuente</strong></summary><blockquote><p>Actualizado: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta de Archivo</th><th>Número de Línea</th></tr></thead><tbody><tr><td>Lógica principal de actualización de skills</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L14-L150" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>14-150</td></tr><tr><td>Actualización desde ruta local</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L64-L82" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>64-82</td></tr><tr><td>Actualización desde repositorio Git</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L85-L125" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>85-125</td></tr><tr><td>Copiar skill desde directorio</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L152-L163" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>152-163</td></tr><tr><td>Verificación de seguridad de ruta</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L165-L172" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>165-172</td></tr><tr><td>Definición de estructura de metadatos</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L8-L15" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>8-15</td></tr><tr><td>Leer metadatos de skill</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L17-L27" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>17-27</td></tr><tr><td>Escribir metadatos de skill</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L29-L36" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>29-36</td></tr><tr><td>Definición de comando CLI</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/cli.ts#L58-L62" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>58-62</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>SKILL_METADATA_FILE = &#39;.openskills.json&#39;</code>: nombre del archivo de metadatos, registra el origen de instalación del skill</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>updateSkills(skillNames)</code>: función principal para actualizar skills especificados o todos los skills</li><li><code>updateSkillFromDir(targetPath, sourceDir)</code>: copia skill desde directorio fuente al directorio objetivo</li><li><code>isPathInside(targetPath, targetDir)</code>: verifica seguridad de ruta de instalación (previene recorrido de ruta)</li><li><code>readSkillMetadata(skillDir)</code>: lee metadatos del skill</li><li><code>writeSkillMetadata(skillDir, metadata)</code>: escribe/actualiza metadatos del skill</li></ul><p><strong>Reglas de negocio</strong>:</p><ul><li><strong>BR-5-1</strong>: por defecto actualiza todos los skills instalados (update.ts:37-38)</li><li><strong>BR-5-2</strong>: soporta lista de nombres de skills separados por comas (update.ts:15)</li><li><strong>BR-5-3</strong>: omite skills sin metadatos de origen (update.ts:56-62)</li><li><strong>BR-5-4</strong>: soporta actualización desde ruta local (update.ts:64-82)</li><li><strong>BR-5-5</strong>: soporta actualización desde repositorio git (update.ts:85-125)</li><li><strong>BR-5-6</strong>: verifica seguridad de ruta (update.ts:156-162)</li></ul></details>`,75)])])}const m=e(t,[["render",o]]);export{h as __pageData,m as default};
